// Track polling iteration count and merge with status response
let pollCount = 0;
try {
  const prev = $('Track Poll Count').first().json;
  pollCount = (prev.poll_count || 0) + 1;
} catch {
  // First iteration — node has no prior execution
  pollCount = 1;
}

const statusData = $input.first().json;

return [{
  json: {
    run_id: statusData.run_id,
    status: statusData.status,
    high_risk_count: statusData.high_risk_count ?? 0,
    transactions_scored: statusData.transactions_scored ?? 0,
    duplicates_found: statusData.duplicates_found ?? 0,
    started_at: statusData.started_at ?? null,
    completed_at: statusData.completed_at ?? null,
    poll_count: pollCount
  }
}];

// Format the anomaly alert for notification
const runData = $('Track Poll Count').first().json;
const transactions = $input.all().map(item => item.json);
const topTxns = transactions.slice(0, 10);

const lines = [
  '🚨 *LeakWatch Anomaly Alert*',
  '',
  `Analysis Run: ${runData.run_id}`,
  `Completed: ${runData.completed_at || 'N/A'}`,
  `Transactions Scored: ${runData.transactions_scored}`,
  `High Risk Found: ${runData.high_risk_count}`,
  `Duplicates Found: ${runData.duplicates_found}`,
  '',
  '*Top High-Risk Transactions:*'
];

for (const txn of topTxns) {
  const factors = (txn.risk_factors || []).join(', ');
  lines.push(
    `• ${txn.voucher_number} — P=${(txn.leak_probability || 0).toFixed(3)} [${factors}]${txn.is_duplicate ? ' ⚠️ DUPLICATE' : ''}`
  );
}

lines.push('', 'Review immediately in the LeakWatch dashboard.');

return [{
  json: {
    text: lines.join('\n'),
    summary: `LeakWatch detected ${runData.high_risk_count} high-risk transactions out of ${runData.transactions_scored} scored.`,
    run_id: runData.run_id,
    high_risk_count: runData.high_risk_count,
    transactions_scored: runData.transactions_scored,
    duplicates_found: runData.duplicates_found,
    top_transactions: topTxns
  }
}];

